    if arr.len() <= 1 {
        return;
    }
    let mid = arr.len() / 2;
    merge_sort(&mut arr[..mid]);
    merge_sort(&mut arr[mid..]);
    let mut result = Vec::new();
    let mut i = 0;
    let mut j = mid;
    while i < mid && j < arr.len() {
        if arr[i] <= arr[j] {
            result.push(arr[i].clone());
            i += 1;
        } else {
            result.push(arr[j].clone());
            j += 1;
        }
