type EventHandler<T = void> = T extends void ? () =>void : (data: T) =>void;

class TypedEventEmitter<TEvents extends Record<string,unknown>> {
  private handlers = new Map<keyof TEvents,Set<EventHandler<any>>>();

  on<K extends keyof TEvents>(
    event: K,handler: EventHandler<TEvents[K]>,): void {
    if (!this.handlers.has(event)) {
      this.handlers.set(event,new Set());
    }
    this.handlers.get(event)!.add(handler);
  }

  off<K extends keyof TEvents>(
    event: K,handler: EventHandler<TEvents[K]>,): void {
    this.handlers.get(event)?.delete(handler);
  }

  emit<K extends keyof TEvents>(event: K,data: TEvents[K]): void {
    this.handlers.get(event)?.forEach((handler) =>handler(data));
  }
}
```

