#[track_caller]
pub(crate) fn test_rng()->rand_xorshift::XorShiftRng {
    let mut hasher = RandomState::new().build_hasher();
    Location::caller().hash(&mut hasher);
    let hc64 = hasher.finish();
    let seed_vec = hc64
        .to_le_bytes()
        .into_iter()
        .chain(0u8..8)
        .collect::<Vec<u8>>();
    let seed: [u8; 16] = seed_vec.as_slice().try_into().unwrap();
